INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Fu ling', '茯苓', 'Poria cocos (Schw.) Wolf', 'Pachyme', 'NEUTRAL', '10 à 15g', 'Fu ling pi : partie la plus superficielle du champignon, noire et grise ; action diurétique bien plus marquée (dans Wu pi yin, avec Sang bai pi, Sheng jiang pi, Chen pi et Da fu pi) ; on doit doubler son dosage, de 15 à 30g. Chi fu ling : partie superficielle, d''une couleur légèrement rosée ; fait s''écouler l''Humidité-Chaleur, traite les maladies lin (avec Che qian zi, Zhi zi etc.). Fu shen : partie profonde, autour de la racine du pin ; calme fortement l''esprit (avec Yuan zhi, Long chi, etc.).', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients qui font s’écouler l’eau, réduisent les œdèmes et les gonflements'));
