INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Hong hua', '紅花', 'Carthamus tinctorius L.', 'Carthame des teinturiers', 'WARM', '3 à 9g', 'Annexe : Fan hong hua / Zang hong hua (番紅花 / 藏紅花) — Safran, Crocus sativus L. Nature : douce, légèrement froide, tropisme Cœur-Foie. Actions : active le sang et chasse la stase, désobstrue les méridiens, rafraîchit le sang et résout la toxicité. Indications : douleurs menstruelles du post-partum, traumatologie, induration douloureuse de l''épigastre, macules et papules suite à une maladie fébrile. Posologie : 1 à 1,5g. Grande prudence pendant la grossesse.', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients qui activent le sang et régularisent les règles Huo xue tiao jing yao 活血調經藥'));
