INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Shi chang pu', '石菖蒲', 'Acorus tatarinowii Schott.', NULL, 'WARM', '5 à 10g', 'Indications diverses : eczéma, furoncles, abcès, gale, douleurs traumatiques et obstructions douloureuses causées par le Vent-Humidité. Traite les mucosités sans forme qui obstruent les orifices, transforme l''humidité trouble.', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients qui ouvrent les orifices Kai qiao yao 開竅藥'));
