INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Tian nan xing', '天南星 (膽南星)', 'Arisaema erubescens (Wall.) Schott, ou A. heterophyllum Bl., ou A. amurense Maxim.', NULL, 'WARM', '3 à 10g', 'Toxique. Dan nan xing (膽南星) est la forme dérivée préparée avec la bile : nature fraîche, saveur amère et légèrement piquante, posologie 3 à 6g. Effets spécifiques au Dan nan xing : clarifie la Chaleur et transforme les mucosités ; calme le Vent interne et stabilise la frayeur. En cas de surdosage ou d''empoisonnement : se gargariser avec du jus de gingembre et 30 à 60 mL de vinaigre de cuisine, et boire 5 mL de jus de gingembre ; décoction de Sheng jiang 30g, Fang feng 60g, Gan cao 15g pendant plusieurs jours jusqu''à disparition des symptômes.', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients qui réchauffent et transforment les mucosités Froid Wen hua han tan yao 溫化寒痰藥'));
