INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Ban xia', '半夏', 'Pinellia ternata (Thunb.) Breit.', NULL, 'WARM', '3 à 10 g', 'Nature toxique. Plusieurs préparations existent : Sheng ban xia (crue, toxique, usage externe uniquement, réduit les gonflements et disperse les nodosités) ; Qing ban xia (préparée à l''alun de potassium, performante pour assécher les mucosités Humidité, dissiper les sensations de plénitude pi man, et harmoniser l''Estomac) ; Jiang ban xia (préparée à l''alun de potassium et au jus de gingembre, performante pour abaisser le contre-courant et arrêter les nausées et vomissements) ; Fa ban xia (préparée avec de la chaux et de la réglisse, performante pour assécher les mucosités Humidité au niveau du Poumon). En cas de surdosage ou d''empoisonnement : Sheng jiang 30g, Lü dou 30g, Fang feng 60g, Gan cao 15g, décoction dans 300 mL, faire un gargarisme avec une moitié et boire l''autre moitié.', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients qui réchauffent et transforment les mucosités Froid Wen hua han tan yao 溫化寒痰藥'));
