INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Dang gui', '當歸', 'Angelica sinensis Diels.', 'Angélique chinoise', 'WARM', '5 à 15g', 'Dang gui tou (當歸頭) : partie supérieure de la racine ; tropisme au haut du corps, arrête les saignements. Dang gui shen (當歸身) : corps de la racine sans radicelles ; tropisme au tronc, tonifie davantage le sang. Dang gui wei (當歸尾) : radicelles ; tropisme au bas du corps, brise le sang et les stases.', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients qui tonifient le sang Bu xue yao 補血藥'));
