INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Niu xi', '川牛膝', 'Cyathula officinalis Kuan', NULL, 'NEUTRAL', '6 à 15 g', 'La fiche présente deux variantes principales : Chuan niu xi (川牛膝, Cyathula officinalis) et Huai niu xi, avec des indications partiellement distinctes selon la variante (mention Chuan ou Huai entre parenthèses dans les effets). La nature ''équilibré'' correspond à neutre (NEUTRAL).', 0, (SELECT id FROM drug_category WHERE name = 'Unknown'));
