INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Yuan hua', '芫花', 'Daphne genkwa Sieb. et Zucc.', 'Daphné', 'WARM', '1.5 à 3g en décoction, 0,6g en poudre', 'Nature toxique. Pour l''usage externe : réduire en poudre fine et mélanger à de la graisse de porc, à appliquer directement sur les lésions (abcès, furoncles, teigne, etc.) ; associer éventuellement à Xiong huang. Était à une époque utilisée localement pour traiter les douleurs dentaires.', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients purgatifs drastiques qui éliminent l’eau'));
