INSERT INTO drug_contraindications (drug_id, contraindication) VALUES ((SELECT id FROM drugs WHERE chinese_name = 'Yuan hua'), 'Toxique et drastique ; peut provoquer une détresse respiratoire en cas de surdosage, voire perte de connaissance et convulsions');
