INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Huang lian', '黃連', 'Coptis chinensis Franch., C. deltoidea C. Y. Cheng et Hsiao, C. teeta Wall.', 'Coptide chinois', 'COLD', '2 à 10g en décoction, 3 à 5g en poudre', 'Préparations dérivées : Sheng huang lian (séchée crue) — clarifie efficacement le feu du Cœur et l''Humidité Chaleur des intestins ; Jiu huang lian (préparée à l''alcool) — clarifie le Feu et la Chaleur du haut du corps (yeux rouges, aphtes, etc.) ; Jiang huang lian (préparée au gingembre) — clarifie le feu du foyer médian, arrête les vomissements et traite les intrications de Froid, Chaleur et Humidité ; Zhu yu huang lian (sautée avec Wu zhu yu) — traite l''agression de l''Estomac par le Foie avec vomissements et régurgitations.', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients qui clarifient la Chaleur et assèchent l’Humidité'));
