INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Ge gen', '葛根', 'Pueraria lobata (Willd.) Ohwi, P. thomsonii Benth.', 'Kudzu', 'COOL', '10 à 20g', 'Ge hua 葛花 : bouton de fleur. Douce, équilibrée, tropisme à l''Estomac. Réveille la Rate et l''Estomac, résout la toxicité de l''alcool. Avec Mu xiang, Chen pi, Zhu ling, Bai dou kou etc., contre la gueule de bois. Avec Huang lian, Long dan cao, Yin chen hao etc. lorsque l''abus d''alcool provoque de l''Humidité Chaleur. Posologie : 3 à 12g.', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients (piquants et frais) qui libèrent la surface du Vent-Chaleur'));
