INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Lu jiao', '鹿角', 'Cervus nippon Temminck, C. elaphus Linnaeus', 'Corne ossifiée de cerf (sika ou élaphe)', 'WARM', '5 à 15g, en décoction ou en poudre', 'La nature est décrite comme tiède à chaude selon les sources. Annexes : Lu jiao jiao 鹿角膠 (colle de corne de cerf) : douce, salée, tiède, tropisme Foie-Reins. Tonifie le Foie et les Reins, soutient le Jing et le sang, arrête les saignements. Posologie : 5 à 10g à dissoudre, ou à prendre en pilule ou en sirop. Lu jiao shuang 鹿角霜 (résidus osseux restant après la préparation de Lu jiao jiao, corne sans gélatine) : salée, tiède, tropisme Foie-Reins. Soutient le Yang des Reins, mobilise le sang. Moins saturant mais moins de potentiel tonique, avec une certaine astringence (peut arrêter les saignements et refermer les plaies). Posologie : 10 à 15g.', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients qui tonifient le Yang Bu yang yao 補陽藥'));
