INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Long gu', '龍骨', 'Os fossilisés de vertébrés préhistoriques', 'Os fossilisés de vertébrés préhistoriques', 'NEUTRAL', '15 à 30g', 'Nature décrite comme équilibrée (neutre), légèrement froide selon certaines sources. La forme calcinée (duan Long gu) est utilisée pour l''effet astringent (consolidation du biao, resserre les orifices, aide à la cicatrisation des plaies et génération des chairs). Yaoyao pour calmer l''esprit par la lourdeur, notamment associé à Mu li. Annexe : Long chi (龍齒) — Dents et défenses fossilisées de mammifères préhistoriques. Saveur : douce, astringente. Nature : fraîche. Tropisme : Cœur et Poumon. Mouvement : descendant, immergent. Posologie : 15 à 30g. Contre-indiqué en cas d''émissions nocturnes causées par la Chaleur, d''Humidité-Chaleur ou d''atteintes simples du biao. Doit subir une précuisson. Effet principal : calme le Cœur et apaise l''Esprit (folie furieuse, palpitations, insomnies, rêves abondants, épilepsie, convulsions infantiles). Plus performant que Long gu pour ancrer le Yang et calmer l''esprit, mais moins polyvalent.', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients lourds qui stabilisent et calment l’esprit Zhong zhen an shen yao 重鎮安神藥'));
