INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Chuan lian zi', '川楝子', 'Melia toosendan Sieb. et Zucc.', NULL, 'COLD', '3 à 10g', 'Légèrement toxique. En cas de surdosage ou d''empoisonnement : décoction avec un peu de sucre blanc et de réglisse. Peut être préparé sauté (chao) pour réduire sa nature froide, ou préparé au vinaigre (cu zhi) pour mobiliser le Qi et arrêter les douleurs. En usage externe : réduit en poudre puis mélangé à un corps gras pour faire un onguent (traitement de la teigne).', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients qui régularisent le Qi Li qi yao 理氣藥'));
